#!/usr/bin/env node
// Generates daemon/src/embedded.ts from the template files, so the CLI/daemon has them
// inlined — required for a single-file binary (SEA), and it simplifies the container too.
// Run automatically by the daemon build. Do not edit embedded.ts by hand.
import { readFileSync, writeFileSync } from "node:fs";
import { dirname, join } from "node:path";
import { fileURLToPath } from "node:url";

const ROOT = join(dirname(fileURLToPath(import.meta.url)), "..");
const T = join(ROOT, "daemon", "templates");
const read = (f) => readFileSync(join(T, f), "utf8");

const out = `// AUTO-GENERATED by scripts/gen-embedded.mjs — do not edit.
export const TRACE2E_COMMAND_MD = ${JSON.stringify(read("trace2e.md"))};
export const SAMPLE_SIGNUP_JSON = ${JSON.stringify(read("sample-signup.json"))};
export const DASHBOARD_HTML = ${JSON.stringify(read("dashboard.html"))};
`;

writeFileSync(join(ROOT, "daemon", "src", "embedded.ts"), out);
console.error("[trace2e] generated daemon/src/embedded.ts");
